noncompliant:
// Noncompliant: Exception not passed to logger
try
{
    ProcessData();
}
catch (Exception ex)
{
    logger.LogError("An error occurred"); // Noncompliant
}

// Noncompliant: Only logging exception message
try
{
    SaveFile();
}
catch (IOException ex)
{
    logger.LogError("IO Error: {0}", ex.Message); // Noncompliant
}

compliant:
// Compliant: Exception passed as parameter
try
{
    ProcessData();
}
catch (Exception ex)
{
    logger.LogError(ex, "An error occurred"); // Compliant
}

// Compliant: Full exception logged
try
{
    SaveFile();
}
catch (IOException ex)
{
    logger.LogError(ex, "IO Error occurred"); // Compliant
}
